        var sum int64 = 0
        for _, num := range nums {
            sum += num
        }
        return sum
    }

    sort.Slice(segments, func(i, j int) bool {
        if segments[i][0] == segments[j][0] {
            return segments[i][1] < segments[j][1]
        }
        return segments[i][0] < segments[j][0]
