func solve(nums []int64, k int64) int64 {
    n := len(nums)
    if n == 0 {
        return 0
    }

    current := int64(0)
    S := make(map[int64]bool)
    S[0] = true
    removable := false
    for i := 0; i < n; i++ {
        current = (current + nums[i]) % k
        if current < 0 {
            current += k
        }
        if _, exists := S[current]; exists {
            if i == n-1 {
                removable = true
            }
            current = 0
            S = make(map[int64]bool)
            S[0] = true
        } else {
            S[current] = true
        }
    }
    if removable {
        return 0
    }

    actualP := make([]int64, n+1)
    modP := make([]int64, n+1)
    actualP[0] = 0
    modP[0] = 0
    for i := 1; i <= n; i++ {
        actualP[i] = actualP[i-1] + nums[i-1]
        modP[i] = actualP[i] % k
        if modP[i] < 0 {
            modP[i] += k
        }
    }

    l := 0
    minRemaining := actualP[n]
    currentSet := make(map[int64]bool)

    for r := 0; r <= n; r++ {
        modVal := modP[r]
        for l < r && currentSet[modVal] {
            delete(currentSet, modP[l])
            l++
        }
        currentSet[modVal] = true
        if r > l {
            segSum := actualP[r] - actualP[l]
            if segSum < minRemaining {
                minRemaining = segSum
            }
        }
    }

    return minRemaining
}
